static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
  assert(Cases.size() >= 1);

  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
  for (size_t I = 1, E = Cases.size(); I != E; ++I) {
    if (Cases[I - 1]->getValue() != Cases[I]->getValue() + 1)
      return false;
  }
  return true;
}

static Value *getCmpIntrinsicValueForCases(Value *Cond,
                                           ArrayRef<ConstantInt *> Cases,
                                           IRBuilder<> &Builder) {
  auto *CI = dyn_cast<CmpIntrinsic>(Cond);
  if (!CI || Cases.empty())
    return nullptr;

  auto *Ty = cast<IntegerType>(CI->getType());
  APInt Min = Cases.front()->getValue();
  APInt Max = Cases.back()->getValue();
  if (!Ty->isValueValidForType(Min) || !Ty->isValueValidForType(Max))
    return nullptr;

  if (Min.isAllOnes() && Max.isZero())
    return Builder.CreateICmp(CI->getGTPredicate(), CI->getLHS(), CI->getRHS(),
                              "switch");
  if (Min.isZero() && Max.isOne())
    return Builder.CreateICmp(CI->getLTPredicate(), CI->getLHS(), CI->getRHS(),
                              "switch");
  if (Min.isZero() && Max.isZero())
    return Builder.CreateICmpEQ(CI->getLHS(), CI->getRHS(), "switch");

  return nullptr;
}
